const item = $input.first();
const body = item.json.body || item.json;

const usuario_id = body.usuario_id;
const prompt = (body.prompt || '').trim();
const wardrobeItems = body.wardrobe_items || [];

if (!usuario_id || !prompt) {
  throw new Error('Faltan campos: usuario_id y prompt son requeridos');
}

if (!Array.isArray(wardrobeItems) || wardrobeItems.length < 4) {
  throw new Error('Se necesitan al menos 4 prendas en el armario');
}

const wardrobeText = wardrobeItems.map((item, index) => {
  return `Prenda ${index + 1} (ID: ${item.post_id}):\n  - Pie de foto: ${item.pie_foto || 'Sin descripción'}\n  - Descripción: ${item.descripcion_prenda || 'Sin detalles'}`;
}).join('\n\n');

const promptCompleto = `Eres un estilista profesional experto en moda. Tu tarea es seleccionar EXACTAMENTE 4 prendas del armario del usuario para crear un outfit coherente y atractivo.

PROMPT DEL USUARIO:
"${prompt}"

ARMARIO DISPONIBLE (${wardrobeItems.length} prendas):
${wardrobeText}

INSTRUCCIONES:
1. Analiza el prompt del usuario y el armario disponible
2. Selecciona EXACTAMENTE 4 prendas que combinen bien entre sí
3. Las prendas deben formar un outfit completo (ej: top, bottom, zapatos, accesorio/capa)
4. Considera colores, estilos y ocasión de uso
5. Genera un nombre creativo y atractivo para el outfit (máximo 120 caracteres)
6. Explica brevemente por qué elegiste estas prendas

RESPONDE ÚNICAMENTE EN FORMATO JSON:
{
  "post_ids": [id1, id2, id3, id4],
  "nombre": "Nombre del outfit",
  "descripcion": "Explicación de por qué estas prendas combinan bien"
}

MUY IMPORTANTE: Los post_ids deben ser EXACTAMENTE 4 números enteros de las prendas listadas arriba.`;

return [{
  json: {
    usuario_id,
    prompt_usuario: prompt,
    prompt_completo: promptCompleto,
    total_prendas: wardrobeItems.length,
    wardrobe_items: wardrobeItems
  }
}];

