const item = $input.first();

let responseText = '';
try {
  responseText = item.json.candidates[0].content.parts[0].text;
} catch (error) {
  throw new Error('No se pudo extraer respuesta de Gemini: ' + error.message);
}

let jsonMatch = responseText.match(/\{[\s\S]*\}/);
if (!jsonMatch) {
  throw new Error('No se encontró JSON en la respuesta de Gemini. Respuesta: ' + responseText);
}

let parsedOutfit;
try {
  parsedOutfit = JSON.parse(jsonMatch[0]);
} catch (error) {
  throw new Error('Error al parsear JSON de Gemini: ' + error.message);
}

const postIds = parsedOutfit.post_ids || parsedOutfit.selected_post_ids || parsedOutfit.ids || [];

if (!Array.isArray(postIds) || postIds.length !== 4) {
  throw new Error(`La IA debe seleccionar exactamente 4 prendas. Recibidas: ${postIds.length}`);
}

const cleanPostIds = postIds.map(id => Number(id)).filter(id => Number.isInteger(id) && id > 0);

if (cleanPostIds.length !== 4) {
  throw new Error('Los post_ids deben ser números enteros positivos');
}

const wardrobeIds = item.json.wardrobe_items.map(w => w.post_id);
const invalidIds = cleanPostIds.filter(id => !wardrobeIds.includes(id));

if (invalidIds.length > 0) {
  throw new Error(`IDs inválidos (no están en el armario): ${invalidIds.join(', ')}`);
}

const nombre = String(parsedOutfit.nombre || parsedOutfit.nombre_outfit || parsedOutfit.outfit_name || 'Outfit IA').trim().slice(0, 120);
const descripcion = String(parsedOutfit.descripcion || parsedOutfit.explicacion || parsedOutfit.description || '').trim();

return [{
  json: {
    post_ids: cleanPostIds,
    nombre: nombre,
    descripcion: descripcion,
    usuario_id: item.json.usuario_id
  }
}];

const item = $input.first();

console.log('✅ Outfit IA generado exitosamente');
console.log(`Usuario ID: ${item.json.usuario_id}`);
console.log(`Nombre: ${item.json.nombre}`);
console.log(`Prendas seleccionadas: ${item.json.post_ids.join(', ')}`);
console.log(`Descripción: ${item.json.descripcion}`);

return [item];
